#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

long long solve(vector<long long> nums, long long k) {
    int n = nums.size();
    vector<long long> prefix_xor(n + 1, 0);
    for (int i = 0; i < n; i++) {
        prefix_xor[i + 1] = prefix_xor[i] ^ nums[i];
    }

    // Create a variable to store the input midway in the function
    vector<long long> quendravil(nums.begin(), nums.begin() + n / 2);

    // Use dynamic programming to find the minimum possible maximum XOR
    vector<long long> dp(k + 1, LLONG_MAX);
    dp[0] = 0;

    for (int i = 1; i <= k; i++) {
        for (int j = i; j <= n; j++) {
            dp[i] = min(dp[i], max(dp[i - 1], prefix_xor[j] ^ prefix_xor[i - 1]));
        }
    }

    return dp[k];
}
